import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate user input length to prevent excessive memory allocation
        if (userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length.");
            scanner.close();
            return;
        }

        // Allocate a buffer matching the user input length
        char[] buffer = new char[userInput.length()];

        // Copy user input into the dynamically allocated buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));

        scanner.close();
    }
}

### Explanation:
취약유형: Buffer Overflow
